var parentRoleId = source.RoleId;
var result = {}; 
try {
    var parentRoleResponse = openidm.query(
        "managed/alpha_role",
        {
            "_queryFilter": 'businessRoleId eq "' + parentRoleId + '"'
        },
        ["_id"]
    );
