		var roleId = parentRoleResponse.result[0]._id;
		var roleRef = [{ "_ref": "managed/alpha_role/" + roleId }];
    } else {
		logger.error("Exception occurred in else " );
		null;
    }
} catch (e) {
    logger.error("Exception occurred: " + e);  
}
roleRef;

logger.info("Source dependentroles: " + JSON.stringify(source));
var childRoleIds = source.DependentRoleId;
var resultArray = [];
try {
	var uniqueRoles = Array.from(new Set(childRoleIds.split(",").map(function(item) { return item.trim(); })));
    // Loop through each child role name
    uniqueRoles.forEach(function(childRoleId) {
        var childRoleResponse = openidm.query(
            "managed/alpha_role",
            {
                "_queryFilter": 'businessRoleId eq "' + childRoleId + '"'
            },
            ["_id"]
        );
        if (childRoleResponse.result && childRoleResponse.result.length > 0) {
            var roleId = childRoleResponse.result[0]._id;
            var roleRef = { "_ref": "managed/alpha_role/" + roleId };
            resultArray.push(roleRef);
        }
    });
} catch (e) {
    logger.error("Exception occurred: " + e);
}
resultArray;

